model.star_schema_warehouse.metricflow_t.raw_code:
-- MetricFlow time spine model (required by dbt Semantic Layer)
{{
    config(
        materialized='table',
        meta={'time_spine': true}
    )
}}

with days as (
    {{
        dbt_utils.date_spine(
            datepart="day",
            start_date="cast('2020-01-01' as date)",
            end_date="dateadd(year, 3, current_date())"
        )
    }}
)

select cast(date_day as date) as date_day
from days

model.elementary.anomaly_threshold_sensi.raw_code:
{{ config(materialized="view", bind=False) }}

with
    metrics_anomaly_score as (select * from {{ ref("metrics_anomaly_score") }}),

    score_sensitivity as (

        select
            full_table_name,
            column_name,
            metric_name,
            latest_metric_value,
            training_avg as metric_avg,
            training_stddev as metric_stddev,
            anomaly_score,
            {{ elementary.edr_condition_as_boolean("abs(anomaly_score) >= 1.5") }}
            as {{ elementary.edr_quote_column("is_anomaly_1_5") }},
            {{ elementary.edr_condition_as_boolean("abs(anomaly_score) >= 2") }}
            as {{ elementary.edr_quote_column("is_anomaly_2") }},
            {{ elementary.edr_condition_as_boolean("abs(anomaly_score) >= 2.5") }}
            as {{ elementary.edr_quote_column("is_anomaly_2_5") }},
            {{ elementary.edr_condition_as_boolean("abs(anomaly_score) >= 3") }}
            as {{ elementary.edr_quote_column("is_anomaly_3") }},
            {{ elementary.edr_condition_as_boolean("abs(anomaly_score) >= 3.5") }}
            as {{ elementary.edr_quote_column("is_anomaly_3_5") }},
            {{ elementary.edr_condition_as_boolean("abs(anomaly_score) >= 4") }}
            as {{ elementary.edr_quote_column("is_anomaly_4") }},
            {{ elementary.edr_condition_as_boolean("abs(anomaly_score) >= 4.5") }}
            as {{ elementary.edr_quote_column("is_anomaly_4_5") }}
        from metrics_anomaly_score
        where abs(anomaly_score) >= 1.5

    )

select *
from score_sensitivity

