macro.elementary.get_anomaly_scores_quer.macro_sql:
{% macro get_anomaly_scores_query(
    test_metrics_table_relation,
    model_relation,
    test_configuration,
    metric_names,
    column_name=none,
    columns_only=false,
    metric_properties=none,
    data_monitoring_metrics_table=none
) %}
    {%- set model_graph_node = elementary.get_model_graph_node(model_relation) %}
    {%- set full_table_name = elementary.model_node_to_full_name(model_graph_node) %}
    {%- set test_execution_id = elementary.get_test_execution_id() %}
    {%- set test_unique_id = elementary.get_test_unique_id() %}
    {%- if not data_monitoring_metrics_table %}
        {#  data_monitoring_metrics_table is none except for integration-tests that test the get_anomaly_scores_query macro,
          and in which case it holds mock history metrics #}
        {%- set data_monitoring_metrics_table = elementary.get_elementary_relation(
            "data_monitoring_metrics"
        ) %}
    {%- endif %}

    {%- if elementary.is_incremental_model(model_graph_node) %}
        {%- set latest_full_refresh = elementary.get_latest_full_refresh(
            model_graph_node
        ) %}
    {%- else %} {%- set latest_full_refresh = none %}
    {%- endif %}

    {%- if test_configuration.seasonality == "day_of_week" %}
        {%- set bucket_seasonality_expr = elementary.edr_day_of_week_expression(
            "bucket_end"
        ) %}
        {%- set has_seasonality = true %}

    {%- elif test_configuration.seasonality == "hour_of_day" %}
        {%- set bucket_seasonality_expr = elementary.edr_hour_of_day_expression(
            "bucket_end"
        ) %}
        {%- set has_seasonality = true %}

    {%- elif test_configuration.seasonality == "hour_of_week" %}
        {%- set bucket_seasonality_expr = elementary.edr_hour_of_week_expression(
            "bucket_end"
        ) %}
        {%- set has_seasonality = true %}

    {%- else %}
        {%- set bucket_seasonality_expr = elementary.const_as_text("no_seasonality") %}
        {%- set has_seasonality = false %}
    {%- endif %}

    {# Build PARTITION BY clause for window functions dynamically to work around Redshift limitation.

       Redshift doesn't allow constant expressions in PARTITION BY of window functions. When seasonality 
       is not configured, bucket_seasonality becomes a constant ('no_seasonality'::text), which triggers 
       the error "constant expressions are not supported in partition by clauses."

       We build the partition keys dynamically, always including the core metric keys and only appending 
       bucket_seasonality when it's computed from timestamps (has_seasonality = true). Partitioning by 
       a constant has no effect anyway, so this preserves behavior while keeping Redshift happy. #}
    {%- set partition_by_keys = "metric_name, full_table_name, column_name, dimension, dimension_value" %}
    {%- if has_seasonality %}
        {%- set partition_by_keys = partition_by_keys ~ ", bucket_seasonality" %}
    {%- endif %}

    {%- set detection_end = elementary.get_detection_end(
        test_configuration.detection_delay
    ) %}
    {%- set detection_end_expr = elementary.edr_cast_as_timestamp(
        elementary.edr_datetime_to_sql(detection_end)
    ) %}
    {%- set min_bucket_start_expr = elementary.get_trunc_min_bucket_start_expr(
        detection_end, metric_properties, test_configuration.days_back
    ) %}

    {# Calculate detection period start for exclusion logic.
       backfill_days defines the window of recent data to test for anomalies on each run.
       It defaults to 2 days (configurable via vars.backfill_days or test-level parameter).
       The detection period spans from (detection_end - backfill_days) to detection_end.
       When exclude_detection_period_from_training is enabled, metrics in this detection period
       are excluded from training statistics to prevent contamination from potentially anomalous data. #}
    {%- if test_configuration.exclude_detection_period_from_training %}
        {%- set detection_period_start = detection_end - modules.datetime.timedelta(
            days=test_configuration.backfill_days
        ) %}
        {%- set detection_period_start_expr = elementary.edr_cast_as_timestamp(
            elementary.edr_datetime_to_sql(detection_period_start)
        ) %}
    {%- endif %}

    {# For timestamped tests, this will be the bucket start, and for non-timestamped tests it will be the
       bucket end (which is the actual time of the test) #}
    {%- set metric_time_bucket_expr = "case when bucket_start is not null then bucket_start else bucket_end end" %}

    {%- set exclude_filter = (
        "should_exclude_from_training = "
        ~ elementary.edr_boolean_literal(false)
    ) -%}

    {%- set anomaly_scores_query %}
        {% if test_configuration.timestamp_column %}
            with buckets as (
                select edr_bucket_start, edr_bucket_end
                from ({{ elementary.complete_buckets_cte(metric_properties, min_bucket_start_expr,
                                                         detection_end_expr) }}) results
                where edr_bucket_start >= {{ min_bucket_start_expr }}
                  and edr_bucket_end <= {{ detection_end_expr }}
            ),
        {% else %}
            with
        {% endif %}
        data_monitoring_metrics as (

            select
                id,
                full_table_name,
                column_name,
                metric_name,
                metric_type,
                metric_value,
                source_value,
                bucket_start,
                bucket_end,
                bucket_duration_hours,
                updated_at,
                dimension,
                dimension_value,
                metric_properties
            from {{ data_monitoring_metrics_table }}
            -- We use bucket_end because non-timestamp tests have only bucket_end field.
            where
                bucket_end > {{ min_bucket_start_expr }}
                {% if test_configuration.timestamp_column %}
                    -- For timestamped tests, verify that the bucket we got from the history is actually
                    -- a valid one (this check is important for buckets that are not aligned with a day).
                    and {{ elementary.edr_multi_value_in(
                        [elementary.edr_cast_as_timestamp('bucket_start'), elementary.edr_cast_as_timestamp('bucket_end')],
                        ['edr_bucket_start', 'edr_bucket_end'],
                        'buckets'
                    ) }}
                {% endif %}
                and metric_properties = {{ elementary.dict_to_quoted_json(metric_properties) }}
                {% if latest_full_refresh %}
                    and updated_at > {{ elementary.edr_cast_as_timestamp(elementary.edr_quote(latest_full_refresh)) }}
                {% endif %}
                and upper(full_table_name) = upper('{{ full_table_name }}')
                and metric_name in {{ elementary.strings_list_to_tuple(metric_names) }}
                {%- if column_name %}
                    and upper(column_name) = upper('{{ column_name }}')
                {%- endif %}
                {%- if columns_only %}
                    and column_name is not null
                {%- endif %}
                {% if test_configuration.dimensions %}
                    and dimension = {{ elementary.edr_quote(elementary.join_list(test_configuration.dimensions, '; ')) }}
                {% endif %}
        ),

        union_metrics as (

            select * from data_monitoring_metrics
            union all
            select * from {{ test_metrics_table_relation }}

        ),

        grouped_metrics_duplicates as (

            select
                id,
                full_table_name,
                column_name,
                metric_name,
                metric_value,
                source_value,
                bucket_start,
                bucket_end,
                bucket_duration_hours,
                updated_at,
                dimension,
                dimension_value,

                -- Fields added for the anomaly_exclude_metrics expression used below
                {{ metric_time_bucket_expr }} as metric_time_bucket,
                {{ elementary.edr_cast_as_date(elementary.edr_date_trunc('day', metric_time_bucket_expr))}} as metric_date,

                row_number() over (partition by id order by updated_at desc) as row_num
            from union_metrics

        ),

        grouped_metrics as (

            select
                id as metric_id,
                full_table_name,
                column_name,
                dimension,
                dimension_value,
                metric_name,
                metric_value,
                source_value,
                bucket_start,
                bucket_end,
                {{ bucket_seasonality_expr }} as bucket_seasonality,
                {{ elementary.edr_condition_as_boolean(test_configuration.anomaly_exclude_metrics) }} as is_excluded,
                {# Flag detection period metrics for exclusion from training #}
                {% if test_configuration.exclude_detection_period_from_training %}
                    {{ elementary.edr_condition_as_boolean('bucket_end > ' ~ detection_period_start_expr) }}
                {% else %}
                    {{ elementary.edr_boolean_literal(false) }}
                {% endif %} as should_exclude_from_training,
                bucket_duration_hours,
                updated_at
            from grouped_metrics_duplicates
            where row_num = 1
        ),

        time_window_aggregation as (

            select
                metric_id,
                full_table_name,
                column_name,
                dimension,
                dimension_value,
                metric_name,
                metric_value,
                source_value,
                bucket_start,
                bucket_end,
                bucket_seasonality,
                bucket_duration_hours,
                updated_at,
                should_exclude_from_training,
                avg(case when {{ exclude_filter }} then metric_value end) over (partition by {{ partition_by_keys }} order by bucket_end asc rows between unbounded preceding and current row) as training_avg,
                {{ elementary.standard_deviation('case when ' ~ exclude_filter ~ ' then metric_value end') }} over (partition by {{ partition_by_keys }} order by bucket_end asc rows between unbounded preceding and current row) as training_stddev,
                count(case when {{ exclude_filter }} then metric_value end) over (partition by {{ partition_by_keys }} order by bucket_end asc rows between unbounded preceding and current row) as training_set_size,
                last_value(case when {{ exclude_filter }} then bucket_end end) over (partition by {{ partition_by_keys }} order by bucket_end asc rows between unbounded preceding and current row) training_end,
                first_value(case when {{ exclude_filter }} then bucket_end end) over (partition by {{ partition_by_keys }} order by bucket_end asc rows between unbounded preceding and current row) as training_start
            from grouped_metrics
                where {{ elementary.edr_is_false('is_excluded') }}
                group by metric_id, full_table_name, column_name, dimension,
                         dimension_value, metric_name, metric_value, source_value,
                         bucket_start, bucket_end, bucket_seasonality,
                         bucket_duration_hours, updated_at, should_exclude_from_training
        ),

        anomaly_scores as (

            select
                {{ elementary.generate_surrogate_key([
                 'metric_id',
                 elementary.const_as_string(test_execution_id)
                ]) }} as id,
                metric_id,
                {{ elementary.const_as_string(test_execution_id) }} as test_execution_id,
                {{ elementary.const_as_string(test_unique_id) }} as test_unique_id,
                {{ elementary.current_timestamp_column() }} as detected_at,
                full_table_name,
                column_name,
                metric_name,
                case
                    when {{ elementary.edr_normalize_stddev('training_stddev') }} is null then null
                    when training_set_size = 1 then null  -- Single value case - no historical context for anomaly detection
                    when {{ elementary.edr_normalize_stddev('training_stddev') }} = 0 then 0  -- Stationary data case - valid, all values are identical
                    else (metric_value - training_avg) / ({{ elementary.edr_normalize_stddev('training_stddev') }})
                end as anomaly_score,
                {{ test_configuration.anomaly_sensitivity }} as anomaly_score_threshold,
                source_value as anomalous_value,
                {{ elementary.edr_cast_as_timestamp('bucket_start') }} as bucket_start,
                {{ elementary.edr_cast_as_timestamp('bucket_end') }} as bucket_end,
                bucket_seasonality,
                metric_value,

                {% set limit_values =  elementary.get_limit_metric_values(test_configuration) %}
                case
                    when {{ elementary.edr_normalize_stddev('training_stddev') }} is null or training_set_size = 1 then null
                    when {{ limit_values.min_metric_value }} > 0 or metric_name in {{ elementary.to_sql_list(elementary.get_negative_value_supported_metrics()) }} then {{ limit_values.min_metric_value }}
                    else 0
                end as min_metric_value,
                case 
                    when {{ elementary.edr_normalize_stddev('training_stddev') }} is null or training_set_size = 1 then null
                    else {{ limit_values.max_metric_value }}
                end as max_metric_value,
                training_avg,
                {{ elementary.edr_normalize_stddev('training_stddev') }} as training_stddev,
                training_set_size,
                {{ elementary.edr_cast_as_timestamp('training_start') }} as training_start,
                {{ elementary.edr_cast_as_timestamp('training_end') }} as training_end,
                dimension,
                dimension_value
            from time_window_aggregation
            where
                metric_value is not null
                and training_avg is not null
        )

        select * from anomaly_scores
    {% endset %}
    {{ return(anomaly_scores_query) }}
{% endmacro %}

macro.elementary.get_limit_metric_values.macro_sql:
{% macro get_limit_metric_values(test_configuration) %}
    {%- set normalized_stddev = elementary.edr_normalize_stddev("training_stddev") -%}
    {%- set min_val -%}
      ((-1) * {{ test_configuration.anomaly_sensitivity }} * {{ normalized_stddev }} + training_avg)
    {%- endset -%}

    {% if test_configuration.ignore_small_changes.drop_failure_percent_threshold %}
        {%- set drop_avg_threshold -%}
        ((1 - {{ test_configuration.ignore_small_changes.drop_failure_percent_threshold }}/100.0) * training_avg)
        {%- endset -%}
        {%- set min_val -%}
        {{ elementary.arithmetic_min(drop_avg_threshold, min_val) }}
        {%- endset -%}
    {% endif %}

    {%- set max_val -%}
      ({{ test_configuration.anomaly_sensitivity }} * {{ normalized_stddev }} + training_avg)
    {%- endset -%}

    {% if test_configuration.ignore_small_changes.spike_failure_percent_threshold %}
        {%- set spike_avg_threshold -%}
        ((1 + {{ test_configuration.ignore_small_changes.spike_failure_percent_threshold }}/100.0) * training_avg)
        {%- endset -%}
        {%- set max_val -%}
        {{ elementary.arithmetic_max(spike_avg_threshold, max_val) }}
        {%- endset -%}
    {% endif %}

    {{ return({"min_metric_value": min_val, "max_metric_value": max_val}) }}
{% endmacro %}

macro.elementary.store_anomaly_test_resu.macro_sql:
{% macro store_anomaly_test_results(flattened_test, anomaly_scores_sql) %}
    {% set anomaly_scores_groups_rows = {} %}
    {% set anomaly_scores_rows = elementary.agate_to_dicts(
        elementary.run_query(anomaly_scores_sql)
    ) %}
    {% for anomaly_scores_row in anomaly_scores_rows %}
        {% set anomaly_scores_group = (
            anomaly_scores_row.full_table_name,
            anomaly_scores_row.column_name,
            anomaly_scores_row.metric_name,
        ) %}
        {% do anomaly_scores_groups_rows.setdefault(anomaly_scores_group, []) %}
        {% do anomaly_scores_groups_rows[anomaly_scores_group].append(
            anomaly_scores_row
        ) %}
    {% endfor %}

    {% set elementary_test_results_rows = [] %}
    {% for anomaly_scores_group, anomaly_scores_rows in anomaly_scores_groups_rows.items() %}
        {% do elementary.debug_log(
            "Found {} anomaly scores for group {}.".format(
                anomaly_scores_rows | length, anomaly_scores_group
            )
        ) %}
        {% do elementary_test_results_rows.append(
            elementary.get_anomaly_test_result_row(
                flattened_test, anomaly_scores_rows
            )
        ) %}
    {% endfor %}
    {% do elementary.cache_elementary_test_results_rows(elementary_test_results_rows) %}
{% endmacro %}

macro.elementary.get_anomaly_test_result.macro_sql:
{% macro get_anomaly_test_result_row(flattened_test, anomaly_scores_rows) %}
    {%- set latest_row = anomaly_scores_rows[-1] %}
    {%- set rows_with_score = (
        anomaly_scores_rows | rejectattr("anomaly_score", "none") | list
    ) %}
    {%- set full_table_name = elementary.insensitive_get_dict_value(
        latest_row, "full_table_name"
    ) %}
    {%- set test_unique_id = flattened_test.unique_id %}
    {%- set test_configuration = elementary.get_cache(test_unique_id) %}
    {%- set test_params = dict(
        elementary.insensitive_get_dict_value(flattened_test, "test_params")
    ) %}
    {%- do test_params.update(test_configuration) %}
    {%- set parent_model_unique_id = elementary.insensitive_get_dict_value(
        flattened_test, "parent_model_unique_id"
    ) %}
    {%- set column_name = elementary.insensitive_get_dict_value(
        latest_row, "column_name"
    ) %}
    {%- set metric_name = elementary.insensitive_get_dict_value(
        latest_row, "metric_name"
    ) %}
    {%- set test_unique_id = elementary.insensitive_get_dict_value(
        latest_row, "test_unique_id"
    ) %}
    {%- if not rows_with_score %}
        {% do elementary.edr_log(
            "Not enough data to calculate anomaly scores on `{}`".format(
                test_unique_id
            )
        ) %}
    {% endif %}
    {%- set test_results_query -%}
      select * from ({{ sql }}) results
      where
        anomaly_score is not null and
        upper(full_table_name) = upper({{ elementary.const_as_string(full_table_name) }}) and
        metric_name = {{ elementary.const_as_string(metric_name) }}
        {%- if column_name %}
          and upper(column_name) = upper({{ elementary.const_as_string(column_name) }})
        {%- endif %}
    {%- endset -%}
    {% set test_results_description %}
      {% if rows_with_score %}
          {{ elementary.insensitive_get_dict_value(rows_with_score[-1], 'anomaly_description') }}
      {% else %}
          Not enough data to calculate anomaly score.
      {% endif %}
    {% endset %}
    {% set failures = namespace(data=0) %}
    {% set filtered_anomaly_scores_rows = [] %}
    {% for row in anomaly_scores_rows %}
        {% if row.anomaly_score is not none %}
            {% do filtered_anomaly_scores_rows.append(row) %}
            {% if row.is_anomalous %}
                {% set failures.data = failures.data + 1 %}
            {% endif %}
        {% endif %}
    {% endfor %}
    {% set test_result_dict = {
        "id": elementary.insensitive_get_dict_value(latest_row, "id"),
        "data_issue_id": elementary.insensitive_get_dict_value(
            latest_row, "metric_id"
        ),
        "model_unique_id": parent_model_unique_id,
        "column_name": column_name,
        "test_type": "anomaly_detection",
        "test_sub_type": metric_name,
        "test_results_description": test_results_description,
        "other": elementary.insensitive_get_dict_value(
            latest_row, "anomalous_value"
        ),
        "test_results_query": test_results_query,
        "test_params": test_params,
        "result_rows": filtered_anomaly_scores_rows,
        "failures": failures.data,
    } %}
    {% set elementary_test_row = elementary.get_dbt_test_result_row(flattened_test) %}
    {% do elementary_test_row.update(test_result_dict) %}
    {% do return(elementary_test_row) %}
{% endmacro %}

