macro.elementary.column_monitors_by_type.macro_sql:
{% macro column_monitors_by_type(data_type, chosen_monitors=none) %}
    {% set normalized_data_type = elementary.normalize_data_type(data_type) %}
    {% set monitors = [] %}
    {% set chosen_monitors = chosen_monitors or elementary.get_agg_column_monitors(
        only_defaults=true
    ) %}
    {% set available_monitors = elementary.get_available_monitors() %}

    {% set any_type_monitors = elementary.lists_intersection(
        chosen_monitors, available_monitors["column_any_type"]
    ) %}
    {% do monitors.extend(any_type_monitors) %}
    {% if normalized_data_type == "numeric" %}
        {% set numeric_monitors = elementary.lists_intersection(
            chosen_monitors, available_monitors["column_numeric"]
        ) %}
        {% do monitors.extend(numeric_monitors) %}
    {% elif normalized_data_type == "string" %}
        {% set string_monitors = elementary.lists_intersection(
            chosen_monitors, available_monitors["column_string"]
        ) %}
        {% do monitors.extend(string_monitors) %}
    {% elif normalized_data_type == "boolean" %}
        {% set boolean_monitors = elementary.lists_intersection(
            chosen_monitors, available_monitors["column_boolean"]
        ) %}
        {% do monitors.extend(boolean_monitors) %}
    {% endif %}
    {{ return(monitors | unique | list) }}
{% endmacro %}

