macro.elementary.get_timestamp_table_que.macro_sql:
{% macro get_timestamp_table_query(
    monitored_table,
    metric_properties,
    timestamp_column,
    table_metrics,
    min_bucket_start,
    max_bucket_end,
    full_table_name_str
) %}
    {%- set timestamp_col_expr = elementary.edr_cast_as_timestamp(
        elementary.escape_reserved_keywords(timestamp_column)
    ) -%}

    with
        partially_time_filtered_monitored_table as (
            select
                {{ timestamp_col_expr }} as monitored_table_timestamp_column
                {%- if metric_properties.timestamp_column and metric_properties.event_timestamp_column %}
                    ,
                    {{
                        elementary.edr_cast_as_timestamp(
                            elementary.escape_reserved_keywords(
                                metric_properties.event_timestamp_column
                            )
                        )
                    }} as monitored_table_event_timestamp_column
                {%- endif %}
            from {{ monitored_table }}
            -- Freshness metric calculated differences between consecutive buckets,
            -- thus the first diff
            -- is always null. Therefore we let few old buckets inside the query and
            -- filter them later, just for
            -- the first relevant diff not to be null
            where
                {{ timestamp_col_expr }}
                >= {{
                    elementary.edr_timeadd(
                        "day",
                        -7,
                        elementary.edr_cast_as_timestamp(min_bucket_start),
                    )
                }}
                {% if metric_properties.where_expression %}
                    and {{ metric_properties.where_expression }}
                {% endif %}
        ),
        monitored_table as (
            select *
            from partially_time_filtered_monitored_table
            where
                monitored_table_timestamp_column
                >= {{ elementary.edr_cast_as_timestamp(min_bucket_start) }}
        ),
        buckets as (
            select edr_bucket_start, edr_bucket_end
            from
                (
                    {{
                        elementary.complete_buckets_cte(
                            metric_properties, min_bucket_start, max_bucket_end
                        )
                    }}
                ) results
            where
                edr_bucket_start
                >= {{ elementary.edr_cast_as_timestamp(min_bucket_start) }}
                and edr_bucket_end
                <= {{ elementary.edr_cast_as_timestamp(max_bucket_end) }}
        ),

        time_filtered_monitored_table as (
            select
                *,
                {{
                    elementary.get_start_bucket_in_data(
                        "monitored_table_timestamp_column",
                        min_bucket_start,
                        metric_properties.time_bucket,
                    )
                }} as start_bucket_in_data
            from monitored_table
            where
                monitored_table_timestamp_column
                >= (select min(edr_bucket_start) from buckets)
                and monitored_table_timestamp_column
                < (select max(edr_bucket_end) from buckets)
                {# To avoid adding buckets before the table first timestamp #}
                and monitored_table_timestamp_column
                >= (select min(monitored_table_timestamp_column) from monitored_table)
        ),

        metrics as (
            {{ elementary.get_unified_metrics_query(table_metrics, metric_properties) }}
        ),

        metrics_final as (
            select
                {{ elementary.edr_cast_as_string(full_table_name_str) }}
                as full_table_name,
                {{ elementary.null_string() }} as column_name,
                metric_name,
                metric_type,
                {{ elementary.edr_cast_as_float("metric_value") }} as metric_value,
                source_value,
                edr_bucket_start as bucket_start,
                edr_bucket_end as bucket_end,
                {{ elementary.timediff("hour", "edr_bucket_start", "edr_bucket_end") }}
                as bucket_duration_hours,
                {{ elementary.null_string() }} as dimension,
                {{ elementary.null_string() }} as dimension_value,
                {{ elementary.dict_to_quoted_json(metric_properties) }}
                as metric_properties
            from metrics
            where
                (
                    metric_value is not null
                    and cast(metric_value as {{ elementary.edr_type_int() }})
                    < {{ elementary.get_config_var("max_int") }}
                )
                or metric_value is null
        )

{% endmacro %}

macro.elementary.default__get_unified_me.macro_sql:
{% macro default__get_unified_metrics_query(table_metrics, metric_properties) %}
    {# This macro is embedded inside a parent CTE ("metrics as (...)"),
       so we directly UNION ALL the metric queries without a WITH clause. #}
    {%- set metric_queries = [] %}
    {%- for metric in table_metrics %}
        {% set metric_query = elementary.get_metric_query(metric, metric_properties) %}
        {% do metric_queries.append(metric_query) %}
    {%- endfor %}

    {% if not metric_queries %}
        {% if metric_properties.timestamp_column %}
            {% do return(
                elementary.empty_table(
                    [
                        ("edr_bucket_start", "timestamp"),
                        ("edr_bucket_end", "timestamp"),
                        ("metric_name", "string"),
                        ("metric_type", "string"),
                        ("source_value", "string"),
                        ("metric_value", "int"),
                    ]
                )
            ) %}
        {% else %}
            {% do return(
                elementary.empty_table(
                    [
                        ("metric_name", "string"),
                        ("metric_type", "string"),
                        ("metric_value", "int"),
                    ]
                )
            ) %}
        {% endif %}
    {% endif %}

    {%- for metric_query in metric_queries %}
        {{ metric_query }}
        {% if not loop.last %}
            union all
        {% endif %}
    {%- endfor %}
{% endmacro %}

macro.elementary.get_metric_query.macro_sql:
{% macro get_metric_query(metric, metric_properties) %}
    {% if metric_properties.timestamp_column %}
        {% set metrics_macro_mapping = {
            "row_count": elementary.row_count_metric_query,
            "freshness": elementary.freshness_metric_query,
            "event_freshness": elementary.event_freshness_metric_query,
        } %}
    {% else %}
        {% set metrics_macro_mapping = {
            "row_count": elementary.get_no_timestamp_volume_query,
            "event_freshness": elementary.get_no_timestamp_event_freshness_query,
        } %}
    {% endif %}

    {%- set metric_macro = metrics_macro_mapping.get(metric.type) %}
    {%- if not metric_macro %}
        {%- do exceptions.raise_compiler_error(
            "Unable to get macro query for metric '{}'".format(metric.type)
        ) %}
    {%- endif %}

    {%- set metric_query = metric_macro(metric, metric_properties) %}
    {%- if not metric_query %}
        {%- do exceptions.raise_compiler_error(
            "Unable to get query for metric '{}'".format(metric.type)
        ) %}
    {%- endif %}

    {{ metric_query }}
{% endmacro %}

macro.elementary._freshness_lag_expr.macro_sql:
{% macro _freshness_lag_expr() %}
    {{
        elementary.timediff(
            "second",
            elementary.lag("timestamp_val")
            ~ " over (order by timestamp_val)",
            "timestamp_val",
        )
    }}
{% endmacro %}

macro.elementary.fabric___bucket_end_fre.macro_sql:
{% macro fabric___bucket_end_freshness_expr() %}
    {# T-SQL does not support least(); use CASE WHEN instead #}
    {{
        elementary.timediff(
            "second",
            elementary.edr_cast_as_timestamp("max(timestamp_val)"),
            "case when edr_bucket_end < {} then edr_bucket_end else {} end".format(
                elementary.current_timestamp_column(),
                elementary.current_timestamp_column(),
            ),
        )
    }}
{% endmacro %}

macro.elementary.fabric__freshness_metri.macro_sql:
{% macro fabric__freshness_metric_query(metric, metric_properties) %}
    {# Fabric / T-SQL: rewrite without CTEs (nested CTEs are not allowed).
       All intermediate results are expressed as inline subqueries.
       Uses the same helper macros as default__ for shared SQL expressions. #}
    {{ elementary._freshness_final_select(metric) }}
    from (
        select
            *,
            row_number() over (
                partition by edr_bucket_end
                order by case when freshness is null then 1 else 0 end, freshness desc
            ) as row_num
        from (
            {# bucketed consecutive updates freshness #}
            select edr_bucket_start, edr_bucket_end, update_timestamp, freshness
            from buckets
            cross join (
                select *
                from (
                    select
                        timestamp_val as update_timestamp,
                        {{ elementary._freshness_lag_expr() }} as freshness
                    from (
                        select distinct monitored_table_timestamp_column as timestamp_val
                        from partially_time_filtered_monitored_table
                    ) as unique_timestamps_inner
                ) as consecutive_updates_freshness_inner
                where update_timestamp >= (select min(edr_bucket_start) from buckets)
            ) as time_filtered_cuf
            where
                update_timestamp >= edr_bucket_start
                and update_timestamp < edr_bucket_end

            union all

            {# bucket end freshness #}
            select
                edr_bucket_start,
                edr_bucket_end,
                max(timestamp_val) as update_timestamp,
                {{ elementary._bucket_end_freshness_expr() }} as freshness
            from buckets
            cross join (
                select distinct monitored_table_timestamp_column as timestamp_val
                from partially_time_filtered_monitored_table
            ) as unique_timestamps_end
            where timestamp_val < edr_bucket_end
            group by edr_bucket_start, edr_bucket_end
        ) as bucket_all_freshness_metrics
    ) as bucket_freshness_ranked
    where row_num = 1
{% endmacro %}

macro.elementary.event_freshness_metric_.macro_sql:
{% macro event_freshness_metric_query(metric, metric_properties) %}
    {{
        return(
            adapter.dispatch("event_freshness_metric_query", "elementary")(
                metric, metric_properties
            )
        )
    }}
{% endmacro %}

macro.elementary.default__event_freshnes.macro_sql:
{% macro default__event_freshness_metric_query(metric, metric_properties) %}
    select
        edr_bucket_start,
        edr_bucket_end,
        {{ elementary.const_as_string(metric.name) }} as metric_name,
        {{ elementary.const_as_string("event_freshness") }} as metric_type,
        {{
            elementary.edr_cast_as_string(
                "max({})".format("monitored_table_event_timestamp_column")
            )
        }} as source_value,
        {{
            "coalesce(max({}), {})".format(
                elementary.timediff(
                    "second",
                    elementary.edr_cast_as_timestamp(
                        "monitored_table_event_timestamp_column"
                    ),
                    elementary.edr_cast_as_timestamp(
                        "monitored_table_timestamp_column"
                    ),
                ),
                elementary.timediff("second", "edr_bucket_start", "edr_bucket_end"),
            )
        }} as metric_value
    from buckets
    left join time_filtered_monitored_table on (edr_bucket_start = start_bucket_in_data)
    group by edr_bucket_start, edr_bucket_end
{% endmacro %}

macro.elementary.clickhouse__event_fresh.macro_sql:
{% macro clickhouse__event_freshness_metric_query(metric, metric_properties) %}
    select
        edr_bucket_start,
        edr_bucket_end,
        {{ elementary.const_as_string(metric.name) }} as metric_name,
        {{ elementary.const_as_string("event_freshness") }} as metric_type,
        cast(
            max(monitored_table_event_timestamp_column) as Nullable(
                {{ elementary.edr_type_string() }}
            )
        ) as source_value,
        {# In ClickHouse, edr_cast_as_timestamp coalesces NULL to epoch and edr_datediff coalesces NULL to 0,
           so we must explicitly check for NULL before computing timediff to preserve the coalesce fallback logic #}
        case
            when max(monitored_table_event_timestamp_column) is not null
            then
                max(
                    dateDiff(
                        'second',
                        monitored_table_event_timestamp_column,
                        monitored_table_timestamp_column
                    )
                )
            else
                {{
                    elementary.timediff(
                        "second", "edr_bucket_start", "edr_bucket_end"
                    )
                }}
        end as metric_value
    from buckets
    left join time_filtered_monitored_table on (edr_bucket_start = start_bucket_in_data)
    group by edr_bucket_start, edr_bucket_end
{% endmacro %}

