            "https://"
            ~ dbt_cloud_domain
            ~ "/deploy/"
            ~ account_id
            ~ "/projects/"
            ~ dbt_cloud_project_id
            ~ "/jobs/"
            ~ dbt_cloud_job_id
        ) %}
        {% do return(dbt_cloud_job_url) %}
    {% elif orchestrator == "github_actions" %}
