    ) %}
    {% do cur_context.num_runs.update({cur_context.name: 1}) %}

    {# Merge durations and num runs to parent context #}
    {% if duration_context_stack | length > 0 %}
        {% set parent_context = duration_context_stack[-1] %}
        {% for sub_context_name, sub_context_duration in cur_context.durations.items() %}
            {% set full_sub_context_name = (
                parent_context.name ~ "." ~ sub_context_name
            ) %}
            {% set existing_duration = parent_context.durations.get(
                full_sub_context_name, modules.datetime.timedelta()
            ) %}

            {% do parent_context.durations.update(
                {
                    full_sub_context_name: existing_duration
                    + sub_context_duration,
                }
            ) %}
        {% endfor %}
        {% for sub_context_name, sub_context_num_runs in cur_context.num_runs.items() %}
            {% set full_sub_context_name = (
                parent_context.name ~ "." ~ sub_context_name
            ) %}
            {% set existing_num_runs = parent_context.num_runs.get(
                full_sub_context_name, 0
            ) %}

            {% do parent_context.num_runs.update(
                {
                    full_sub_context_name: existing_num_runs
                    + sub_context_num_runs
                }
            ) %}
        {% endfor %}
    {% endif %}

    {% do return(cur_context) %}
{% endmacro %}

