    column_name,
    min_value=none,
    max_value=none,
    inclusive=true,
    context_columns=none
) %}
    {%- if min_value is none and max_value is none %}
        {{
            exceptions.raise_compiler_error(
                "accepted_range_with_context: at least one of min_value or max_value must be provided."
            )
