macro.elementary.get_data_freshness_sla_.macro_sql:
{% macro get_data_freshness_sla_query(
    model_relation,
    timestamp_column,
    sla_deadline_utc,
    target_date,
    target_date_start_utc,
    target_date_end_utc,
    formatted_sla_time,
    timezone,
    where_expression
) %}

    with

        sla_deadline as (
            select
                {{ elementary.edr_cast_as_timestamp("'" ~ sla_deadline_utc ~ "'") }}
                as deadline_utc,
                {{
                    elementary.edr_cast_as_timestamp(
                        "'" ~ target_date_start_utc ~ "'"
                    )
                }} as target_date_start_utc,
                {{ elementary.edr_cast_as_timestamp("'" ~ target_date_end_utc ~ "'") }}
                as target_date_end_utc,
                '{{ target_date }}' as target_date
        ),

        {# Get the max timestamp from the data #}
        max_data_timestamp as (
            select
                max(
                    {{ elementary.edr_cast_as_timestamp(timestamp_column) }}
                ) as max_timestamp
            from {{ model_relation }}
            {% if where_expression %} where {{ where_expression }} {% endif %}
        ),

        {# Determine freshness status #}
        freshness_result as (
            select
                sd.target_date,
                sd.deadline_utc as sla_deadline_utc,
                mdt.max_timestamp,
                case
                    when mdt.max_timestamp is null
                    then 'NO_DATA'
                    {# Data from today or later counts as fresh — this checks whether
                       today's data EXISTS, not whether it arrived before the SLA deadline.
                       The SLA deadline is enforced separately via is_failure. #}
                    when mdt.max_timestamp >= sd.target_date_start_utc
                    then 'DATA_FRESH'
                    else 'DATA_STALE'
                end as freshness_status
            from sla_deadline sd
            cross join max_data_timestamp mdt
        ),

        final_result as (
            select
                '{{ model_relation.identifier }}' as model_name,
                target_date,
                '{{ formatted_sla_time }}' as sla_time,
                '{{ timezone }}' as timezone,
                freshness_status,
                cast(
                    max_timestamp as {{ elementary.edr_type_string() }}
                ) as max_timestamp,
                {{
                    elementary.edr_condition_as_boolean(
                        "freshness_status != 'DATA_FRESH' and "
                        ~ elementary.edr_current_timestamp_in_utc()
                        ~ " > sla_deadline_utc"
                    )
                }} as is_failure,
                {# Use a different alias to avoid shadowing the input column.
                   ClickHouse resolves column refs against output aliases, so
                   keeping the same name would make is_failure compare against
                   the string-cast version, causing a type mismatch. #}
                cast(
                    sla_deadline_utc as {{ elementary.edr_type_string() }}
                ) as sla_deadline_utc_str,
                {# BigQuery does not support '' to escape single quotes inside string literals.
                   Use \' for BigQuery and '' for all other adapters. #}
                {%- if target.type == "bigquery" -%}
                    {%- set escaped_where = (
                        where_expression | replace("'", "\\'")
                        if where_expression
                        else ""
                    ) -%}
                {%- else -%}
                    {%- set escaped_where = (
                        where_expression | replace("'", "''")
                        if where_expression
                        else ""
                    ) -%}
                {%- endif -%}
                {%- set where_suffix = (
                    (" (with filter: " ~ escaped_where ~ ")")
                    if where_expression
                    else ""
                ) -%}
                case
                    when freshness_status = 'NO_DATA'
                    then
                        'No data found in "{{ model_relation.identifier }}"{{ where_suffix }}. Expected data to be updated before {{ formatted_sla_time }} {{ timezone }}.'
                    when freshness_status = 'DATA_STALE'
                    then
                        {{
                            elementary.edr_concat(
                                [
                                    "'Data in \""
                                    ~ model_relation.identifier
                                    ~ "\" is stale. Last update was at '",
                                    "cast(max_timestamp as "
                                    ~ elementary.edr_type_string()
                                    ~ ")",
                                    "', which is before today. Expected fresh data before "
                                    ~ formatted_sla_time
                                    ~ " "
                                    ~ timezone
                                    ~ ".'",
                                ]
                            )
                        }}
                    else
                        {{
                            elementary.edr_concat(
                                [
                                    "'Data in \""
                                    ~ model_relation.identifier
                                    ~ "\" is fresh, last update at '",
                                    "cast(max_timestamp as "
                                    ~ elementary.edr_type_string()
                                    ~ ")",
                                    "' (before SLA deadline "
                                    ~ formatted_sla_time
                                    ~ " "
                                    ~ timezone
                                    ~ ").'",
                                ]
                            )
                        }}
                end as result_description
            from freshness_result
        )

    select
        model_name,
        target_date,
        sla_time,
        timezone,
        sla_deadline_utc_str as sla_deadline_utc,
        freshness_status,
        max_timestamp,
        result_description
    from final_result
    where is_failure = {{ elementary.edr_boolean_literal(true) }}

{% endmacro %}

