            {%- if (meta["referenced_columns"] or none) is iterable -%}
                {%- for exposure_column in meta["referenced_columns"] -%}
                    {#
                        Each column in 'referenced_columns' has the following property:

                        'column_name'

                        Optionally, you can specify the following properties:

                        'data_type' - the specific data type of the column

                        'node' - the ref to the source node of the specific column used in the exposure

                    #}
                    {%- if matching_exposures | length > 1 and "node" not in exposure_column -%}
                        {%- do elementary.edr_log_warning(
                            "missing node property for the exposure: "
                            ~ exposure["name"]
                            ~ " which not the only exposure depending on "
                            ~ model
                            ~ ", We're not able to verify the column level dependencies of this exposure"
                        ) -%}
                    {%- elif matching_exposures | length == 1 or (
                        context["render"](
                            elementary.get_rendered_ref(
                                (exposure_column["node"] or "")
                            )
                        )
                        == context["render"](model | lower)
                    ) -%}
                        {%- if exposure_column[
                            "column_name"
                        ] | upper not in columns_dict.keys() -%}
                            {%- do invalid_exposures.append(
                                {
                                    "exposure": exposure["name"],
                                    "url": exposure["url"],
                                    "error": exposure_column["column_name"]
                                    ~ " column missing in the model",
                                }
                            ) -%}
                            {%- elif (
                                exposure_column["data_type"] or ""
                            ) != "" and exposure_column[
                                "data_type"
                            ] != columns_dict[
                                exposure_column["column_name"] | upper
                            ] -%}
                            {%- do invalid_exposures.append(
                                {
                                    "exposure": exposure["name"],
                                    "url": exposure["url"],
                                    "error": "different data type for the column "
                                    ~ exposure_column["column_name"]
                                    ~ " "
                                    ~ exposure_column["data_type"]
                                    ~ " vs "
                                    ~ columns_dict[
                                        exposure_column["column_name"]
                                        | upper
                                    ],
                                }
                            ) -%}
                        {%- endif -%}
                    {%- endif -%}
                {%- endfor -%}
            {%- else -%}
                {%- do elementary.edr_log_warning(
                    "missing meta property for the exposure: "
                    ~ exposure["name"]
                    ~ ", We're not able to verify the column level dependencies of this exposure"
                ) -%}
            {%- endif -%}
        {%- endfor -%}
        {%- if invalid_exposures | length > 0 -%}
            {%- for invalid_exposure in invalid_exposures %}
                {{ 'UNION ALL ' if not loop.first }}
                select
                    '{{ invalid_exposure["exposure"] }}' as exposure,
                    '{{ invalid_exposure["url"] }}' as url,
                    '{{ invalid_exposure["error"] }}' as error
            {%- endfor -%}
        {%- else -%} {{ elementary.no_results_query() }}
        {%- endif -%}
    {%- else -%} {{ elementary.no_results_query() }}

    {%- endif -%}
    {{ elementary.test_log("end", full_table_name, "exposure validation") }}

