            error_if=">=2",
        )
    }}

    {%- if execute and elementary.is_test_command() and elementary.is_elementary_enabled() %}

        {% if warn_threshold_percent < 0 or error_threshold_percent < 0 %}
            {{
                exceptions.raise_compiler_error(
                    "warn_threshold_percent and error_threshold_percent must be non-negative"
                )
            }}
        {% endif %}
        {% if min_row_count < 0 %}
            {{ exceptions.raise_compiler_error("min_row_count must be non-negative") }}
        {% endif %}
        {% if warn_threshold_percent > error_threshold_percent %}
            {{
                exceptions.raise_compiler_error(
                    "warn_threshold_percent cannot exceed error_threshold_percent"
                )
            }}
        {% endif %}
        {% if direction not in ["both", "spike", "drop"] %}
            {{
                exceptions.raise_compiler_error(
                    "direction must be 'both', 'spike', or 'drop'"
                )
            }}
        {% endif %}

        {% set model_relation = elementary.get_model_relation_for_test(
            model, elementary.get_test_model()
        ) %}
        {% if not model_relation %}
            {{ exceptions.raise_compiler_error("Unsupported model: " ~ model) }}
        {% endif %}

        {%- if elementary.is_ephemeral_model(model_relation) %}
            {{
                exceptions.raise_compiler_error(
                    "Test not supported for ephemeral models: "
                    ~ model_relation.identifier
                )
            }}
        {%- endif %}

        {# Validate timestamp column exists and is a timestamp type #}
        {% set timestamp_column_data_type = (
            elementary.find_normalized_data_type_for_column(
                model_relation, timestamp_column
            )
        ) %}
        {% if not elementary.is_column_timestamp(
            model_relation, timestamp_column, timestamp_column_data_type
        ) %}
            {{
                exceptions.raise_compiler_error(
                    "Column '"
                    ~ timestamp_column
                    ~ "' is not a timestamp type. The timestamp_column must be a timestamp or datetime column."
                )
            }}
        {% endif %}

        {# Collect row_count metrics using Elementary's shared infrastructure.
           This handles: incremental bucket detection, metric computation, temp table creation, cache storage.
           Pass time_bucket as-is (none = use model/project default via get_time_bucket). #}
        {% set table_metrics = [{"type": "row_count", "name": "row_count"}] %}
        {% do elementary.collect_table_metrics(
            table_metrics=table_metrics,
            model_expr=model,
            model_relation=model_relation,
            timestamp_column=timestamp_column,
            time_bucket=time_bucket,
            days_back=days_back,
            backfill_days=backfill_days,
            where_expression=where_expression,
            dimensions=[],
        ) %}

        {# Build metric_properties to match the filter used by collect_table_metrics.
           This must produce the same dict so our data_monitoring_metrics query matches. #}
        {% set model_graph_node = elementary.get_model_graph_node(model_relation) %}
        {% set metric_props = elementary.get_metric_properties(
            model_graph_node,
            timestamp_column,
            where_expression,
            time_bucket,
            [],
        ) %}

        {# Compare current vs previous bucket, combining cached history + newly computed metrics #}
        {{
            elementary.get_volume_threshold_comparison_query(
                model_relation=model_relation,
                metric_props=metric_props,
                warn_threshold_percent=warn_threshold_percent,
                error_threshold_percent=error_threshold_percent,
                direction=direction,
                min_row_count=min_row_count,
            )
        }}

    {%- else %} {{ elementary.no_results_query() }}
    {%- endif %}
{% endtest %}

macro.elementary.handle_tests_results.macro_sql:
{% macro handle_tests_results() %}
    {{ elementary.file_log("Handling test results.") }}
    {% set cached_elementary_test_results = elementary.get_cache(
        "elementary_test_results"
    ) %}
    {% set cached_elementary_test_failed_row_counts = elementary.get_cache(
        "elementary_test_failed_row_counts"
    ) %}
    {% set store_result_rows_in_own_table = elementary.get_config_var(
        "store_result_rows_in_own_table"
    ) %}
    {% set elementary_test_results = (
        elementary.get_result_enriched_elementary_test_results(
            cached_elementary_test_results,
            cached_elementary_test_failed_row_counts,
            render_result_rows=(not store_result_rows_in_own_table),
        )
    ) %}
    {% if store_result_rows_in_own_table %}
        {% set test_result_rows = elementary.pop_test_result_rows(
            elementary_test_results
        ) %}
    {% endif %}
    {% set tables_cache = elementary.get_cache("tables") %}
    {% set test_metrics_tables = tables_cache.get("metrics").get("relations") %}
    {% set test_columns_snapshot_tables = tables_cache.get("schema_snapshots") %}
    {% set database_name, schema_name = elementary.get_package_database_and_schema(
        "elementary"
    ) %}
    {% do elementary.insert_data_monitoring_metrics(
        database_name, schema_name, test_metrics_tables
    ) %}
    {% do elementary.insert_schema_columns_snapshot(
        database_name, schema_name, test_columns_snapshot_tables
    ) %}
    {% if test_result_rows %}
        {% set test_result_rows_relation = elementary.get_elementary_relation(
            "test_result_rows"
        ) %}
        {% do elementary.insert_rows(
            test_result_rows_relation,
            test_result_rows,
            should_commit=True,
            chunk_size=elementary.get_config_var("dbt_artifacts_chunk_size"),
        ) %}
    {% endif %}
    {% if elementary_test_results %}
        {% set elementary_test_results_relation = elementary.get_elementary_relation(
            "elementary_test_results"
        ) %}
        {% do elementary.insert_rows(
            elementary_test_results_relation,
            elementary_test_results,
            should_commit=True,
            chunk_size=elementary.get_config_var("dbt_artifacts_chunk_size"),
        ) %}
    {% endif %}
    {% do elementary.file_log("Handled test results successfully.") %}
    {% do return("") %}
{% endmacro %}

macro.elementary.get_normalized_test_sta.macro_sql:
{% macro get_normalized_test_status(result, elementary_test_results_row) %}
    {% set failures = elementary_test_results_row.get("failures", result.failures) %}
    {% set status = result.status %}

    {# For Elementary anomaly tests, we actually save more than one result per test, in that case the dbt status will be "fail"
    even if one such result failed and the rest succeeded. To handle this, we make sure to mark the status as "pass" for these 
    results if the number of failed rows is 0.
    We don't want to do this for every test though - because otherwise it can break configurations like warn_if=0 #}
    {% if failures == 0 and elementary_test_results_row.get(
        "test_type"
    ) == "anomaly_detection" %}
        {% set status = "pass" %}
    {% endif %}

    {% do return(status) %}
{% endmacro %}

macro.elementary.get_result_enriched_ele.macro_sql:
{% macro get_result_enriched_elementary_test_results(
    cached_elementary_test_results,
    cached_elementary_test_failed_row_counts,
    render_result_rows=false
) %}
    {% set elementary_test_results = [] %}

    {% for result in results %}
        {% set result = elementary.get_run_result_dict(result) %}
        {% set node = result.node or elementary.get_node(
            result.unique_id or result.node.unique_id
        ) %}
        {% if node.resource_type == "test" %}
            {% set elementary_test_results_rows = cached_elementary_test_results.get(
                node.unique_id
            ) %}
            {% set elementary_test_failed_row_count = (
                cached_elementary_test_failed_row_counts.get(node.unique_id)
            ) %}

            {# Materializing the test failed and therefore was not added to the cache. #}
            {% if not elementary_test_results_rows %}
                {% set flattened_test = elementary.flatten_test(node) %}
                {% set elementary_test_results_rows = [
                    elementary.get_dbt_test_result_row(flattened_test)
                ] %}
            {% endif %}

            {% for elementary_test_results_row in elementary_test_results_rows %}
                {% set failures = elementary_test_results_row.get(
                    "failures", result.failures
                ) %}
                {% set status = elementary.get_normalized_test_status(
                    result, elementary_test_results_row
                ) %}

                {% do elementary_test_results_row.update(
                    {
                        "status": status,
                        "failures": failures,
                        "invocation_id": invocation_id,
                        "failed_row_count": elementary_test_failed_row_count,
                    }
                ) %}
                {% do elementary_test_results_row.setdefault(
                    "test_results_description", result.message
                ) %}
                {# Add note when test uses sampling #}
                {% set test_params = elementary_test_results_row.get(
                    "test_params", {}
                ) %}
                {% if test_params is mapping and test_params.get(
                    "sample_percent"
                ) is number and test_params.get(
                    "sample_percent"
                ) > 0 and test_params.get(
                    "sample_percent"
                ) < 100 %}
                    {% set base_desc = elementary_test_results_row.get(
                        "test_results_description"
                    ) %}
                    {% set note = "Note: this test uses sample_percent, so result samples may not exactly match the failure count." %}
                    {% set new_desc = (base_desc ~ " " ~ note) if base_desc else note %}
                    {% do elementary_test_results_row.update(
                        {"test_results_description": new_desc}
                    ) %}
                {% endif %}
                {% if render_result_rows %}
                    {% do elementary_test_results_row.update(
                        {
                            "result_rows": elementary.render_result_rows(
                                elementary_test_results_row.result_rows
                            ),
                        }
                    ) %}
                {% endif %}
                {% do elementary_test_results.append(elementary_test_results_row) %}
            {% endfor %}
        {% endif %}
    {% endfor %}

    {% do return(elementary_test_results) %}
{% endmacro %}

macro.elementary.insert_data_monitoring_.macro_sql:
{% macro insert_data_monitoring_metrics(
    database_name, schema_name, test_metrics_tables
) %}
    {%- if not test_metrics_tables %} {% do return(none) %} {% endif %}

    {%- set test_tables_union_query = elementary.union_metrics_query(
        test_metrics_tables
    ) -%}
    {% if not test_tables_union_query %} {% do return(none) %} {% endif %}

    {%- set target_relation = elementary.get_elementary_relation(
        "data_monitoring_metrics"
    ) -%}
    {% if not target_relation %}
        {% do elementary.raise_missing_elementary_models() %}
    {% endif %}

    {%- set temp_relation = elementary.make_temp_view_relation(target_relation) -%}
    {% set insert_query %}
      INSERT INTO {{ target_relation }} (
        id,
        full_table_name,
        column_name,
        metric_name,
        metric_type,
        metric_value,
        source_value,
        bucket_start,
        bucket_end,
        bucket_duration_hours,
        updated_at,
        dimension,
        dimension_value,
        metric_properties,
        created_at
      )
      SELECT
        id,
        full_table_name,
        column_name,
        metric_name,
        metric_type,
        metric_value,
        source_value,
        bucket_start,
        bucket_end,
        bucket_duration_hours,
        updated_at,
        dimension,
        dimension_value,
        metric_properties,
        {{ elementary.edr_current_timestamp() }} as created_at
      FROM {{ temp_relation }}
      {{ elementary.get_query_settings() }}
    {% endset %}

    {{ elementary.file_log("Inserting metrics into {}.".format(target_relation)) }}
    {%- do elementary.edr_create_table_as(
        true, temp_relation, test_tables_union_query
    ) %}
    {% do elementary.run_query(insert_query) %}

    {# DuckDB: commit so insert survives dbt's post-on-run-end ROLLBACK #}
    {% if target.type == "duckdb" %} {% do adapter.commit() %} {% endif %}

    {% if not elementary.has_temp_table_support() %}
        {% do elementary.fully_drop_relation(temp_relation) %}
    {% endif %}
{% endmacro %}

