macro.elementary.get_anomalies_test_conf.macro_sql:
{% macro get_anomalies_test_configuration(
    model_relation,
    mandatory_params,
    timestamp_column,
    where_expression,
    anomaly_sensitivity,
    anomaly_direction,
    min_training_set_size,
    time_bucket,
    days_back,
    backfill_days,
    seasonality,
    freshness_column,
    event_timestamp_column,
    dimensions,
    sensitivity,
    ignore_small_changes,
    fail_on_zero,
    detection_delay,
    anomaly_exclude_metrics,
    detection_period,
    training_period,
    exclude_final_results,
    exclude_detection_period_from_training
) %}

    {%- set model_graph_node = elementary.get_model_graph_node(model_relation) %}
    {# Changes in these configs impact the metric id of the test. #}
    {# If these configs change, we ignore the old metrics and recalculate. #}
    {% set metric_props = elementary.get_metric_properties(
        model_graph_node,
        timestamp_column,
        where_expression,
        time_bucket,
        dimensions,
        freshness_column,
        event_timestamp_column,
    ) %}
    {% set metric_props = elementary.undefined_dict_keys_to_none(metric_props) %}

    {# All anomaly detection tests #}
    {# We had a names mix in sensitivity/anomaly_sensitivity, this keeps backwards competability #}
    {%- set anomaly_sensitivity = (
        sensitivity
        if sensitivity
        else elementary.get_test_argument(
            "anomaly_sensitivity", anomaly_sensitivity, model_graph_node
        )
    ) %}
    {%- set anomaly_direction = elementary.get_anomaly_direction(
        anomaly_direction, model_graph_node
    ) %}
    {%- set detection_period = elementary.get_test_argument(
        "detection_period", detection_period, model_graph_node
    ) -%}
    {%- set backfill_days = elementary.detection_period_to_backfill_days(
        detection_period, backfill_days, model_graph_node
    ) -%}
    {%- set fail_on_zero = elementary.get_test_argument(
        "fail_on_zero", fail_on_zero, model_graph_node
    ) %}

    {# timestamp_column anomaly detection tests #}
    {%- set seasonality = elementary.get_seasonality(
        seasonality,
        model_graph_node,
        metric_props.time_bucket,
        metric_props.timestamp_column,
    ) %}
    {%- set training_period = elementary.get_test_argument(
        "training_period", training_period, model_graph_node
    ) -%}
    {%- set days_back = elementary.training_period_to_days_back(
        training_period, days_back, model_graph_node
    ) -%}
    {%- set days_back = elementary.get_days_back(
        days_back, model_graph_node, seasonality
    ) %}
    {%- set detection_delay = elementary.get_detection_delay(
        detection_delay, model_graph_node
    ) %}

    {%- set ignore_small_changes = elementary.get_test_argument(
        "ignore_small_changes", ignore_small_changes, model_graph_node
    ) %}
    {# Normalize ignore_small_changes to ensure it's always a dict with expected keys #}
    {%- if ignore_small_changes is none %}
        {%- set ignore_small_changes = {
            "spike_failure_percent_threshold": none,
            "drop_failure_percent_threshold": none,
        } %}
    {%- endif %}

    {% set anomaly_exclude_metrics = elementary.get_test_argument(
        "anomaly_exclude_metrics", anomaly_exclude_metrics, model_graph_node
    ) %}
    {% set exclude_final_results = elementary.get_exclude_final_results(
        exclude_final_results
    ) %}
    {% set exclude_detection_period_from_training = elementary.get_test_argument(
        "exclude_detection_period_from_training",
        exclude_detection_period_from_training,
        model_graph_node,
    ) %}

    {% set test_configuration = {
        "timestamp_column": metric_props.timestamp_column,
        "where_expression": metric_props.where_expression,
        "time_bucket": metric_props.time_bucket,
        "freshness_column": metric_props.freshness_column,
        "event_timestamp_column": metric_props.event_timestamp_column,
        "dimensions": metric_props.dimensions,
        "days_back": days_back,
        "backfill_days": backfill_days,
        "anomaly_sensitivity": anomaly_sensitivity,
        "anomaly_direction": anomaly_direction,
        "seasonality": seasonality,
        "ignore_small_changes": ignore_small_changes,
        "fail_on_zero": fail_on_zero,
        "detection_delay": detection_delay,
        "anomaly_exclude_metrics": anomaly_exclude_metrics,
        "exclude_final_results": exclude_final_results,
        "exclude_detection_period_from_training": exclude_detection_period_from_training,
    } %}
    {%- set test_configuration = elementary.undefined_dict_keys_to_none(
        test_configuration
    ) -%}
    {%- do elementary.validate_mandatory_configuration(
        test_configuration, mandatory_params
    ) -%}
    {%- do elementary.validate_ignore_small_changes(test_configuration) -%}

    {# Adding to cache so test configuration will be available outside the test context #}
    {%- set test_unique_id = elementary.get_test_unique_id() %}
    {%- do elementary.set_cache(test_unique_id, test_configuration) -%}
    {{ return([test_configuration, metric_props]) }}
{% endmacro %}

macro.elementary.validate_mandatory_conf.macro_sql:
{% macro validate_mandatory_configuration(test_configuration, mandatory_params) %}
    {%- set mandatory_configuration = [
        "anomaly_sensitivity",
        "anomaly_direction",
        "backfill_days",
    ] %}
    {%- set with_timestamp_mandatory_configuration = ["time_bucket", "days_back"] %}
    {%- set missing_mandatory_params = [] %}

    {%- if mandatory_params and mandatory_params is iterable %}
        {%- set mandatory_configuration = elementary.union_lists(
            mandatory_configuration, mandatory_params
        ) %}
    {%- endif %}
    {%- if test_configuration.timestamp_column %}
        {%- set mandatory_configuration = elementary.union_lists(
            mandatory_configuration, with_timestamp_mandatory_configuration
        ) %}
    {%- endif %}

    {%- for mandatory_param in mandatory_configuration %}
        {%- if test_configuration.get(mandatory_param) is none %}
            {%- do missing_mandatory_params.append(mandatory_param) -%}
