        {% set minute = time_24_match.group(2) | int %}

        {# Validate hour and minute #}
        {% if hour < 0 or hour > 23 %}
            {{
                exceptions.raise_compiler_error(
                    "Invalid hour '"
                    ~ hour
                    ~ "' in time '"
                    ~ sla_time
                    ~ "'. Hour must be 0-23 for 24-hour format."
                )
            }}
        {% endif %}
        {% if minute < 0 or minute > 59 %}
            {{
                exceptions.raise_compiler_error(
                    "Invalid minute '"
                    ~ minute
                    ~ "' in time '"
                    ~ sla_time
                    ~ "'. Minute must be 0-59."
                )
            }}
        {% endif %}

        {% do return({"hour": hour, "minute": minute}) %}
    {% endif %}

    {# Check for hour-only format (just a number, interpreted as 24-hour) #}
    {% set hour_only_pattern = re.compile("^(\\d{1,2})$") %}
    {% set hour_only_match = hour_only_pattern.match(time_str) %}

    {% if hour_only_match %}
        {% set hour = hour_only_match.group(1) | int %}

        {% if hour < 0 or hour > 23 %}
            {{
                exceptions.raise_compiler_error(
                    "Invalid hour '"
                    ~ hour
                    ~ "' in time '"
                    ~ sla_time
                    ~ "'. Hour must be 0-23."
                )
            }}
        {% endif %}

        {% do return({"hour": hour, "minute": 0}) %}
    {% endif %}

    {# No valid format matched #}
    {{
        exceptions.raise_compiler_error(
            "Invalid time format '"
            ~ sla_time
            ~ "'. Supported formats: '7:00', '07:00', '7am', '7:30am', '2pm', '2:30pm', '14:00', '14:30'."
        )
    }}
{% endmacro %}

