macro.elementary.calculate_sla_deadline_.macro_sql:
{% macro calculate_sla_deadline_utc(sla_hour, sla_minute, timezone) %}
    {% set datetime = modules.datetime %}
    {% set pytz = modules.pytz %}

    {% if elementary.is_dbt_fusion() %}
        {# dbt-fusion's pytz.localize() is unreliable (dbt-labs/dbt-fusion#143).
           Use stdlib datetime.timezone.utc to create a proper UTC-aware datetime,
           then call astimezone(pytz_tz) which uses pytz's fromutc() internally —
           more reliable than localize(). #}
        {% set target_tz = pytz.timezone(timezone) %}

        {# Create a UTC-aware datetime using pytz.utc — avoids datetime.timezone which
           is not exposed in fusion's modules.datetime (dbt-labs/dbt-fusion#143) #}
        {% set now_utc_aware = datetime.datetime.now(pytz.utc) %}
        {% set now_local = now_utc_aware.astimezone(target_tz) %}
        {% set target_date_local = now_local.date() %}
        {% set tz_offset = now_local.utcoffset() %}

        {# Keep a naive UTC datetime for final deadline comparison #}
        {% set now_utc = datetime.datetime.utcnow() %}

        {# Build all datetimes as naive local, then convert to naive UTC
           by subtracting the timezone offset. This avoids tz-aware comparison. #}
        {% set day_start_utc = (
            datetime.datetime.combine(
                target_date_local, datetime.time(0, 0, 0)
            )
            - tz_offset
        ) %}

        {% set day_end_utc = (
            datetime.datetime.combine(
                target_date_local, datetime.time(23, 59, 59)
            )
            - tz_offset
        ) %}

        {% set sla_deadline_utc = (
            datetime.datetime.combine(
                target_date_local, datetime.time(sla_hour, sla_minute, 0)
            )
            - tz_offset
        ) %}

        {# Compare naive UTC datetimes #}
        {% set deadline_passed = now_utc > sla_deadline_utc %}
    {% else %}
        {# Standard dbt-core path using pytz.localize() #}
        {% set utc_tz = pytz.timezone("UTC") %}
        {% set target_tz = pytz.timezone(timezone) %}

        {% set now_utc = datetime.datetime.now(utc_tz) %}
        {% set now_local = now_utc.astimezone(target_tz) %}
        {% set target_date_local = now_local.date() %}

        {% set day_start_naive = datetime.datetime.combine(
            target_date_local, datetime.time(0, 0, 0)
        ) %}
        {% set day_start_local = target_tz.localize(day_start_naive, is_dst=False) %}
        {% set day_start_utc = day_start_local.astimezone(utc_tz) %}

        {% set day_end_naive = datetime.datetime.combine(
            target_date_local, datetime.time(23, 59, 59)
        ) %}
        {% set day_end_local = target_tz.localize(day_end_naive, is_dst=False) %}
        {% set day_end_utc = day_end_local.astimezone(utc_tz) %}

        {% set sla_deadline_naive = datetime.datetime.combine(
            target_date_local, datetime.time(sla_hour, sla_minute, 0)
        ) %}
        {% set sla_deadline_local = target_tz.localize(
            sla_deadline_naive, is_dst=False
        ) %}
        {% set sla_deadline_utc = sla_deadline_local.astimezone(utc_tz) %}

        {% set deadline_passed = now_utc > sla_deadline_utc %}
    {% endif %}

    {# Format for SQL #}
    {% set sla_deadline_utc_str = sla_deadline_utc.strftime("%Y-%m-%d %H:%M:%S") %}
    {% set target_date_str = target_date_local.strftime("%Y-%m-%d") %}
    {% set day_start_utc_str = day_start_utc.strftime("%Y-%m-%d %H:%M:%S") %}
    {% set day_end_utc_str = day_end_utc.strftime("%Y-%m-%d %H:%M:%S") %}

    {{
        return(
            {
                "sla_deadline_utc": sla_deadline_utc_str,
                "target_date": target_date_str,
                "target_date_start_utc": day_start_utc_str,
                "target_date_end_utc": day_end_utc_str,
                "deadline_passed": deadline_passed,
                "day_of_week": now_local.strftime("%A"),
                "day_of_month": now_local.day,
            }
        )
    }}
{% endmacro %}

macro.elementary.normalize_day_of_week.macro_sql:
{% macro normalize_day_of_week(day_of_week) %}
    {% set valid_days = [
        "monday",
        "tuesday",
        "wednesday",
        "thursday",
        "friday",
        "saturday",
        "sunday",
    ] %}

    {% if day_of_week is none or day_of_week == "" %} {{ return([]) }} {% endif %}

    {# Convert single value to list #}
    {% if day_of_week is string %} {% set days = [day_of_week] %}
    {% else %} {% set days = day_of_week %}
    {% endif %}

    {# Validate and normalize each day #}
    {% set normalized = [] %}
    {% for day in days %}
        {% set day_lower = day | string | trim | lower %}
        {% if day_lower not in valid_days %}
            {{
                exceptions.raise_compiler_error(
                    "Invalid day_of_week '"
                    ~ day
                    ~ "'. Must be one of: Monday, Tuesday, Wednesday, Thursday, Friday, Saturday, Sunday."
                )
            }}
        {% endif %}
        {% do normalized.append(day_lower) %}
    {% endfor %}

    {{ return(normalized) }}
{% endmacro %}

macro.elementary.normalize_day_of_month.macro_sql:
{% macro normalize_day_of_month(day_of_month) %}
    {% if day_of_month is none or day_of_month == "" %} {{ return([]) }} {% endif %}

    {# Convert single value to list #}
    {% if day_of_month is number %} {% set days = [day_of_month] %}
    {% elif day_of_month is string %} {% set days = [day_of_month | int] %}
    {% else %} {% set days = day_of_month %}
    {% endif %}

    {# Validate each day #}
    {% set normalized = [] %}
    {% for day in days %}
        {% set day_int = day | int %}
        {% if day_int < 1 or day_int > 31 %}
            {{
                exceptions.raise_compiler_error(
                    "Invalid day_of_month '" ~ day ~ "'. Must be between 1 and 31."
                )
            }}
        {% endif %}
        {% do normalized.append(day_int) %}
    {% endfor %}

    {{ return(normalized) }}
{% endmacro %}

macro.elementary.should_check_sla_today.macro_sql:
{% macro should_check_sla_today(
    current_day_of_week,
    current_day_of_month,
    day_of_week_filter,
    day_of_month_filter
) %}
    {# If no filters are set, run every day #}
    {% if day_of_week_filter | length == 0 and day_of_month_filter | length == 0 %}
        {{ return(true) }}
    {% endif %}

    {# Check day of week filter #}
    {% set current_dow_lower = current_day_of_week | lower %}
    {% if current_dow_lower in day_of_week_filter %} {{ return(true) }} {% endif %}

    {# Check day of month filter #}
    {% if current_day_of_month in day_of_month_filter %} {{ return(true) }} {% endif %}

    {# No filter matched #}
    {{ return(false) }}
{% endmacro %}

macro.elementary.validate_unique_metric_.macro_sql:
{% macro validate_unique_metric_names(metrics) %}
    {% set metric_names = [] %}
    {% for metric in metrics %}
        {% if not metric.name %}
            {% do exceptions.raise_compiler_error(
                "The 'name' argument is required for each metric."
            ) %}
        {% endif %}
        {% if metric.name in metric_names %}
            {% do exceptions.raise_compiler_error(
                "The metric '{}' is already defined.".format(metric.name)
            ) %}
        {% endif %}
        {% do metric_names.append(metric.name) %}
    {% endfor %}

    {% set test_node = elementary.get_test_model() %}
    {% set parent_model_unique_ids = (
        elementary.get_parent_model_unique_ids_from_test_node(test_node)
    ) %}

    {% for graph_node in graph.nodes.values() %}
        {% if test_node.unique_id != graph_node.unique_id and graph_node.resource_type == "test" %}
            {% set test_metadata = elementary.safe_get_with_default(
                graph_node, "test_metadata", {}
            ) %}
            {% if test_metadata.namespace == "elementary" and test_metadata.name == "collect_metrics" %}
                {% set test_parent_model_unique_ids = (
                    elementary.get_parent_model_unique_ids_from_test_node(
                        graph_node
                    )
                ) %}
                {% if parent_model_unique_ids == test_parent_model_unique_ids %}
                    {% for metric in test_metadata.kwargs.metrics %}
                        {% if metric.name in metric_names %}
                            {% do exceptions.raise_compiler_error(
                                "The metric '{}' is already defined.".format(
                                    metric.name
                                )
                            ) %}
                        {% endif %}
                    {% endfor %}
                {% endif %}
            {% endif %}
        {% endif %}
    {% endfor %}
{% endmacro %}

