macro.elementary.dremio__edr_dateadd.macro_sql:
{% macro dremio__edr_dateadd(datepart, interval, from_date_or_timestamp) %}
    {% set datepart = datepart | lower %}
    {% if datepart == "year" %}
        timestampadd(
            year,
            cast({{ interval }} as int),
            cast({{ from_date_or_timestamp }} as timestamp)
        )
    {% elif datepart == "quarter" %}
        timestampadd(
            quarter,
            cast({{ interval }} as int),
            cast({{ from_date_or_timestamp }} as timestamp)
        )
    {% elif datepart == "month" %}
        timestampadd(
            month,
            cast({{ interval }} as int),
            cast({{ from_date_or_timestamp }} as timestamp)
        )
    {% elif datepart == "week" %}
        timestampadd(
            week,
            cast({{ interval }} as int),
            cast({{ from_date_or_timestamp }} as timestamp)
        )
    {% elif datepart == "hour" %}
        timestampadd(
            hour,
            cast({{ interval }} as int),
            cast({{ from_date_or_timestamp }} as timestamp)
        )
    {% elif datepart == "minute" %}
        timestampadd(
            minute,
            cast({{ interval }} as int),
            cast({{ from_date_or_timestamp }} as timestamp)
        )
    {% elif datepart == "second" %}
        timestampadd(
            second,
            cast({{ interval }} as int),
            cast({{ from_date_or_timestamp }} as timestamp)
        )
    {% elif datepart == "day" %}
        timestampadd(
            day,
            cast({{ interval }} as int),
            cast({{ from_date_or_timestamp }} as timestamp)
        )
    {% else %}
        {{
            exceptions.raise_compiler_error(
                "dremio__edr_dateadd: unrecognized datepart '"
                ~ datepart
                ~ "'. Supported: year, quarter, month, week, day, hour, minute, second."
